import xmltodict
def parse_xml(file):  # Function to Parse Xml File  
    with open (f'{file}.xml', 'r') as file :    
        data = file.read()      
        
    dict_data= xmltodict.parse(data)     
            
    return dict_data['root']  # Returning the settings in dictionary format